import React, { useState } from 'react';
import { NavLink, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Layout({ children, isAdmin }) {
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout, isAuthenticated } = useAuth();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const tidMatch = location.pathname.match(/\/tournaments\/(\d+)/);
  const tid = tidMatch ? tidMatch[1] : null;

  const mainNav = isAdmin ? [
    { to: '/admin/dashboard', icon: '📊', label: 'Dashboard' },
    { to: '/admin/tournaments', icon: '🏆', label: 'Tournaments' },
  ] : [
    { to: '/dashboard', icon: '📊', label: 'Live Overview' },
    { to: '/fixtures', icon: '📅', label: 'Fixtures' },
  ];

  const tournamentNav = tid ? (isAdmin ? [
    { to: `/admin/tournaments/${tid}`, icon: '📋', label: 'Overview', exact: true },
    { to: `/admin/tournaments/${tid}/teams`, icon: '🛡', label: 'Teams' },
    { to: `/admin/tournaments/${tid}/players`, icon: '🏏', label: 'Players' },
    { to: `/admin/tournaments/${tid}/matches`, icon: '🎯', label: 'Matches' },
    { to: `/admin/tournaments/${tid}/leaderboard`, icon: '📈', label: 'Leaderboard' },
  ] : [
    { to: `/tournaments/${tid}`, icon: '📋', label: 'Overview', exact: true },
    { to: `/tournaments/${tid}/teams`, icon: '🛡', label: 'Teams' },
    { to: `/tournaments/${tid}/players`, icon: '🏏', label: 'Players' },
    { to: `/tournaments/${tid}/leaderboard`, icon: '📈', label: 'Standings' },
  ]) : null;

  const handleLogout = () => {
    logout();
    navigate('/dashboard');
  };

  return (
    <div className="app-layout">
      {/* Mobile overlay */}
      {sidebarOpen && (
        <div onClick={() => setSidebarOpen(false)}
          style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)', zIndex: 199 }} />
      )}

      <aside className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-logo">
          <div className="logo-emblem">🏏</div>
          <div className="logo-text">
            <h2>CRICMANAGER</h2>
            <span>{isAdmin ? '⚙ Admin Portal' : '◉ Live Scores'}</span>
          </div>
        </div>

        <nav className="sidebar-nav">
          <div className="nav-group-label">{isAdmin ? 'Management' : 'Navigation'}</div>
          {mainNav.map(item => (
            <NavLink key={item.to} to={item.to}
              className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
              onClick={() => setSidebarOpen(false)}>
              <span className="nav-icon">{item.icon}</span>
              {item.label}
            </NavLink>
          ))}

          {tournamentNav && (
            <>
              <div className="nav-group-label" style={{ marginTop: 16 }}>Tournament</div>
              {tournamentNav.map(item => (
                <NavLink key={item.to} to={item.to} end={item.exact}
                  className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
                  onClick={() => setSidebarOpen(false)}>
                  <span className="nav-icon">{item.icon}</span>
                  {item.label}
                </NavLink>
              ))}
            </>
          )}

          {isAdmin && (
            <>
              <div className="nav-group-label" style={{ marginTop: 16 }}>Quick Links</div>
              <NavLink to="/dashboard" className="nav-item" style={{ color: 'var(--text-3)', fontSize: 12 }}>
                <span className="nav-icon">👁</span> Public View
              </NavLink>
            </>
          )}
        </nav>

        <div className="sidebar-footer">
          {isAuthenticated ? (
            <div style={{ width: '100%' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
                <span className={`role-badge ${user.role === 'ADMIN' ? 'admin' : 'viewer'}`}>
                  {user.role === 'ADMIN' ? '👑' : '🎯'} {user.role}
                </span>
                <span style={{ flex: 1, fontSize: 12, color: 'var(--text-2)', overflow: 'hidden', textOverflow: 'ellipsis' }}>{user.name}</span>
              </div>
              <button className="btn btn-ghost btn-sm" style={{ width: '100%', justifyContent: 'center' }} onClick={handleLogout}>
                Sign Out
              </button>
            </div>
          ) : (
            <div style={{ width: '100%' }}>
              <div style={{ fontSize: 11, color: 'var(--text-3)', marginBottom: 8 }}>v2.0 · CricManager</div>
              <button className="btn btn-secondary btn-sm" style={{ width: '100%', justifyContent: 'center' }}
                onClick={() => navigate('/login')}>
                Admin Login
              </button>
            </div>
          )}
        </div>
      </aside>

      <main className="main-content">
        {/* Mobile top bar */}
        <div style={{ display: 'none', padding: '12px 16px', background: 'var(--navy-2)', borderBottom: '1px solid var(--card-border)', alignItems: 'center', justifyContent: 'space-between' }}
          className="mobile-topbar">
          <button className="btn btn-ghost btn-sm" onClick={() => setSidebarOpen(true)}>☰</button>
          <span style={{ fontFamily: 'Rajdhani', fontWeight: 700, color: 'var(--gold-light)', letterSpacing: 1 }}>CRICMANAGER</span>
          <div style={{ width: 60 }} />
        </div>
        {children}
      </main>
    </div>
  );
}
